/// Sum the on-wire payload size of the Common-group fields named by `mask`.
///
/// - Returns `None` if `mask` sets a bit outside the CLI-exposed `FIELDS`
///   table — the length is then unknown, so the frame can't be decoded.
/// - 0.3.0-1 limit: only the CLI-7 Common fields are sized; a foreign
///   Common-group field makes its frames undecodable (counted as a resync).
///   Sizing the full Common group is tracked in todo.
fn common_mask_len(mask: u16) -> Option<usize> {
    let mut len = 0usize;
    for bit in 0u8..16 {
        if mask & (1u16 << bit) != 0 {
            len += FIELDS.iter().find(|f| f.bit == bit)?.size;
        }
    }
    Some(len)
}

/// The fields named by `mask`, in bit order — for decoding one sample frame.
fn mask_fields(mask: u16) -> Vec<&'static Field> {
    let mut out: Vec<&'static Field> =
        FIELDS.iter().filter(|f| mask & (1u16 << f.bit) != 0).collect();
    out.sort_by_key(|f| f.bit);
    out
}

/// Outcome of trying to read one binary frame at the front of a buffer.
enum FrameTry {
    /// A complete, CRC-valid Common-group frame of this many bytes.
    Frame(usize),
    /// Not enough bytes yet to decide — wait for more.
    Incomplete,
    /// A false `0xFA` (non-Common group, unknown field, or bad CRC) — resync.
    Invalid,
}

/// Try to recognize a binary frame at `buf[0]` (already known to be `0xFA`).
///
/// Self-describing and passive: reads the groups byte and 16-bit field mask
/// from the frame's own header to compute its length, then checks the trailing
/// CRC-16. Issues no device query — the frame carries everything needed.
fn try_binary_frame(buf: &[u8]) -> FrameTry {
    if buf.len() < BENCH_HEADER {
        return FrameTry::Incomplete;
    }
    if buf[1] != BENCH_GROUPS {
        return FrameTry::Invalid; // only the Common group is decoded
    }
    let mask = u16::from_le_bytes([buf[2], buf[3]]);
    let payload = match common_mask_len(mask) {
        Some(p) => p,
        None => return FrameTry::Invalid, // a field we don't size (CLI-7 limit)
    };
    let frame_len = BENCH_HEADER + payload + BENCH_CRC;
    if buf.len() < frame_len {
        return FrameTry::Incomplete;
    }
    // The CRC runs from the groups byte through the trailing CRC and yields 0.
    if vn_crc16(&buf[1..frame_len]) != 0 {
        return FrameTry::Invalid;
    }
    FrameTry::Frame(frame_len)
}

/// One passive measurement window: the live stream classified into ASCII async
/// lines and binary `0xFA` frames, with one sample of each kind.
///
/// - `total_bytes` is every byte read off the wire (the throughput basis);
///   `ascii_lines` / `bin_frames` are the recognized-message counts.
struct Passive {
    ascii_lines: u64,
    bin_frames: u64,
    total_bytes: u64,
    elapsed: f64,
    ascii_sample: Option<String>,
    bin_sample: Option<String>,
}

/// Read the live stream for `secs` and classify it, writing nothing to the
/// device.
///
/// The VN-100 emits whole messages back-to-back on one UART, so the stream is a
/// sequence of complete units — ASCII async lines (`$VN...\r\n`) and binary
/// `0xFA` frames, possibly time-multiplexed. At each unit boundary the first
/// byte selects the path:
///
/// - `0xFA` — a length-delimited, CRC-checked binary frame.
/// - `$` — a newline-delimited ASCII line, counted if it's a valid async
///   message.
/// - anything else — a stray byte between units; skip it.
fn measure_passive<S: Read>(port: &mut S, secs: u64) -> std::io::Result<Passive> {
    let start = Instant::now();
    let deadline = start + Duration::from_secs(secs);
    let mut buf = [0u8; 1024];
    let mut acc: Vec<u8> = Vec::new();
    let mut p = Passive {
        ascii_lines: 0,
        bin_frames: 0,
        total_bytes: 0,
        elapsed: 0.0,
        ascii_sample: None,
        bin_sample: None,
    };

    while Instant::now() < deadline {
        match port.read(&mut buf) {
            Ok(0) => continue,
            Ok(n) => {
                acc.extend_from_slice(&buf[..n]);
                p.total_bytes += n as u64;
            }
            Err(ref e)
                if matches!(
                    e.kind(),
                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
                ) =>
            {
                continue;
            }
            Err(e) => return Err(e),
        }

        // Consume every complete unit at the front of `acc`; stop at the first
        // incomplete one and let the next read extend it.
        let mut i = 0;
        while i < acc.len() {
            match acc[i] {
                BENCH_SYNC => match try_binary_frame(&acc[i..]) {
                    FrameTry::Frame(len) => {
                        p.bin_frames += 1;
                        if p.bin_sample.is_none() {
                            let mask = u16::from_le_bytes([acc[i + 2], acc[i + 3]]);
                            p.bin_sample =
                                Some(decode_binary_sample(&acc[i..i + len], &mask_fields(mask)));
                        }
                        i += len;
                    }
                    FrameTry::Incomplete => break,
                    FrameTry::Invalid => i += 1,
                },
                b'$' => match acc[i..].iter().position(|&c| c == b'\n') {
                    Some(nl) => {
                        let raw = String::from_utf8_lossy(&acc[i..=i + nl]);
                        let cand = match raw.rfind('$') {
                            Some(pos) => raw[pos..].trim(),
                            None => raw.trim(),
                        };
                        if is_async_line(cand) {
                            p.ascii_lines += 1;
                            if p.ascii_sample.is_none() {
                                p.ascii_sample = Some(cand.to_string());
                            }
                        }
                        i += nl + 1;
                    }
                    None => break, // line not finished yet
                },
                _ => i += 1,
            }
        }
        acc.drain(0..i);
        // Bound memory if the stream is unrecognized (no units consumed).
        if acc.len() > 8192 {
            let keep = acc.len() - 1024;
            acc.drain(0..keep);
        }
    }

    p.elapsed = start.elapsed().as_secs_f64();
    Ok(p)
}

/// Run a passive `bench`: observe the live stream for `secs`, then report the
/// ASCII line rate, binary frame rate, and total wire throughput.
///
/// - Writes nothing to the device — measurement is decoupled from
///   configuration (the `set-*` verbs change the stream).
/// - Errors only if nothing recognizable arrived (likely a wrong `--baud` or a
///   silent device).
fn bench_passive<S: Read>(
    port: &mut S,
    baud: u32,
    secs: u64,
) -> Result<(), Box<dyn std::error::Error>> {
    println!("Measuring the live stream for {secs}s (passive — no device writes)...");
    let p = measure_passive(port, secs)?;

    if p.ascii_lines == 0 && p.bin_frames == 0 {
        return Err(format!(
            "no recognizable VN-100 output in {:.2}s ({} B seen) — is the device streaming, \
             and is --baud {baud} correct?",
            p.elapsed, p.total_bytes
        )
        .into());
    }

    let per = |c: u64| if p.elapsed > 0.0 { c as f64 / p.elapsed } else { 0.0 };
    println!(
        "\nResult over {:.2}s:\n  \
         ASCII  : {} lines  -> {:.1} lines/s\n  \
         binary : {} frames -> {:.1} frames/s  (0xFA-delimited, CRC-checked)\n  \
         wire   : {} bytes  -> {:.2} kB/s",
        p.elapsed,
        p.ascii_lines,
        per(p.ascii_lines),
        p.bin_frames,
        per(p.bin_frames),
        p.total_bytes,
        p.total_bytes as f64 / p.elapsed / 1000.0
    );
    if let Some(s) = &p.ascii_sample {
        println!("  ASCII sample : {s}");
    }
    if let Some(s) = &p.bin_sample {
        println!("  binary sample: {s}");
    }

    // Link utilization from the raw wire bytes (8N1 -> 10 bits/byte).
    let bits = if p.elapsed > 0.0 {
        p.total_bytes as f64 * 10.0 / p.elapsed
    } else {
        0.0
    };
    println!(
        "Wire throughput ~{:.0} kbit/s = {:.0}% of the {:.1} kbit/s {baud}-baud link.",
        bits / 1000.0,
        100.0 * bits / baud as f64,
        baud as f64 / 1000.0
    );
    Ok(())
}

