//! Key VN messages:
//!   $VNRRG,<id>*XX          -> $VNRRG,<id>,<f1>,...*YY   (read register)
//!   $VNWRG,<id>,<f1>,...*XX  -> echo                     (write register)
//!   $VNWNV*XX               -> $VNWNV*YY                 (save all to flash)
//!   $VNERR,<code>*XX                                     (error; see error_description)
